import {
  Body,
  Controller,
  Param,
  ParseUUIDPipe,
  Post,
  Req,
  UseGuards,
} from '@nestjs/common';
import { ApiSecurity, ApiTags } from '@nestjs/swagger';
import {
  ValidateSessionRequest,
  ValidateSessionRequestSchema,
} from '@smartcart/shared-types';
import type { Request } from 'express';
import { ApiKeyGuard, ApiKeyContext } from '../../../../common/guards/api-key.guard';
import { ZodValidationPipe } from '../../../../common/pipes/zod-validation.pipe';
import { CheckoutService } from '../../application/services/checkout.service';

/**
 * POS validation endpoint (README §2.4 POST /sessions/:id/validate, §2.8 W1).
 * Authenticated by POS API Key (NOT JWT). The key's store scope is passed to the
 * service so it can reject keys not scoped to the session's store.
 */
@ApiTags('checkout')
@ApiSecurity('api-key')
@Controller('sessions')
@UseGuards(ApiKeyGuard)
export class ValidationController {
  constructor(private readonly checkout: CheckoutService) {}

  @Post(':id/validate')
  validate(
    @Param('id', ParseUUIDPipe) id: string,
    @Body(new ZodValidationPipe(ValidateSessionRequestSchema))
    dto: ValidateSessionRequest,
    @Req() req: Request & { apiKey?: ApiKeyContext },
  ) {
    return this.checkout.validateSession(id, dto, req.apiKey?.storeId);
  }
}
